public class Car {
  private String brand;
  private String model;
  private int speed;

  public Car(String brand, String model) {
    this.brand = brand;
    this.model = model;
    this.speed = 0;
  }

  public void drive() {
    String message = brand + " " + model + " sürətlə hərəkət edir: " + speed + " km/s";
    System.out.println(message);
  }

  public static void main(String[] args) {
    Car car = new Car("Toyota", "Camry");
    car.drive();
  }
}
// Çıxış: Toyota Camry sürətlə hərəkət edir: 0 km/s

public class Car {
  private String brand;
  private int speed;

  public Car(String brand) {
    this.brand = brand;
    this.speed = 0;
  }

  public void setSpeed(int speed) {
    if (speed >= 0) {
      this.speed = speed;
    } else {
      System.out.println("Sürət mənfi ola bilməz!");
    }
  }

  public int getSpeed() {
    return speed;
  }

  public void display() {
    String message = brand + " sürəti: " + speed + " km/s";
    System.out.println(message);
  }

  public static void main(String[] args) {
    Car car = new Car("Honda");
    car.setSpeed(100);
    car.display();
  }
}
// Çıxış: Honda sürəti: 100 km/s

